{
  "ticket": "TKT-0771",
  "title": "Fix linkedin-metrics.sh python-dateutil dependency",
  "agent": "Forge (infra)",
  "executedAt": "2026-07-14T22:10:00+10:00",
  "decision": "vendor_minimal_iso8601_parser",
  "rationale": "Avoids breaking if system Python changes or python-dateutil is uninstalled/upgrade-blocked. No pip/brew install needed. Maintains identical behaviour for the only token-expiry format LinkedIn emits ('YYYY-MM-DDTHH:MM:SS[.fff]Z' and 'YYYY-MM-DDTHH:MM:SS[+HH:MM]').",
  "changedFiles": [
    "scripts/linkedin-metrics.sh"
  ],
  "verification": {
    "zshSyntaxCheck": {
      "command": "zsh -n scripts/linkedin-metrics.sh",
      "result": "OK"
    },
    "dateutilDependencyRemoved": {
      "command": "python3 -c \"from dateutil import parser\"",
      "result": "ModuleNotFoundError (expected; no longer required by script)"
    },
    "stdlibSufficient": {
      "command": "python3 -c \"from datetime import datetime, timezone, timedelta; print('stdlib OK')\"",
      "result": "stdlib OK; dateutil not required"
    },
    "functionalDryRun": {
      "method": "Extracted the new expiry-check python heredoc into /tmp/tkt-0771-verify.sh and ran 5 cases (past UTC, future UTC, past fractional, empty token, real auth state with past expiry 2026-07-11T00:00:00Z). All produced expected yes/no outputs.",
      "results": "5/5 PASS"
    },
    "endToEndScriptRun": {
      "command": "zsh scripts/linkedin-metrics.sh --post-urn \"urn:li:activity:123456\"",
      "result": "Exited cleanly with 'Token expired' message; no ModuleNotFoundError. External interface and JSON output schema unchanged."
    }
  },
  "externalInterfaceUnchanged": true,
  "outputSchemaUnchanged": true,
  "noLiveLinkedInCall": true,
  "blockers": [],
  "notes": [
    "The original bug was that 'from dateutil import parser as dp' sat at module-level inside the python heredoc, so the import failed before the try/except could fall back to strptime.",
    "The vendored parser is a ~20-line regex-based ISO-8601 reader that handles all formats LinkedIn has ever used for tokenExpiry in this codebase (Z, fractional seconds, +/-HH:MM offsets).",
    "If a future LinkedIn change introduces a new date format, the parser raises ValueError and the script prints 'warn: could not parse tokenExpiry' to stderr and treats the token as non-expired (fail-open) — preserving the original code's behaviour for unparseable dates."
  ]
}
